// ── PN INDEX LOOKUP (dari GitHub via Get PN Index node) ──────────────────────
const pnIndexInput = items.find(i => i.json && i.json._meta);
const pnIndex = pnIndexInput ? (pnIndexInput.json.parts || {}) : {};

function lookupPN(partNo) {
  if (!partNo || !pnIndex[partNo]) return null;
  const d = Array.isArray(pnIndex[partNo]) ? pnIndex[partNo][0] : pnIndex[partNo];
  return {
    fig_no    : d.fig_no,
    fig_name  : d.fig_name,
    page      : d.page,
    ref_no    : d.ref_no,
    part_name_manual: d.part_name,
    // Ganti DRIVE_FILE_ID dengan ID file manual PDF di Google Drive
    drive_link: \`https://drive.google.com/file/d/DRIVE_FILE_ID/preview#page=\${d.page}\`,
  };
}
// ─────────────────────────────────────────────────────────────────────────────

const inputs = $input.all();

let requestData   = [];
let rhData        = [];
let mandatoryData = [];
let reqHeader     = { vessel: "-", department: "-", approver: "-", date: "-", engine: "-" };

// ─── Ambil engine_type dari Webhook ───────────────────────────────────────
try {
    const wb = $('Webhook').first().json;
    if (wb?.body?.engine_type) reqHeader.engine = wb.body.engine_type;
} catch(e) {}

// ─── Parse semua input ────────────────────────────────────────────────────
inputs.forEach(input => {
    const json = input.json;

    // Ambil engine_type jika ada
    if (json?.body?.engine_type && reqHeader.engine === "-") {
        reqHeader.engine = json.body.engine_type;
    }

    let dataArray = [];
    let parsedObj = null;

    // Format: output Gemini (content.parts[0].text)
    if (json?.content?.parts?.[0]?.text) {
        try {
            const clean = json.content.parts[0].text.replace(/```json/g,'').replace(/```/g,'').trim();
            parsedObj = JSON.parse(clean);
            dataArray = Array.isArray(parsedObj) ? parsedObj : (parsedObj.extracted_items || [parsedObj]);
        } catch(e) {}
    }
    // Format: sudah jadi object dengan extracted_items
    else if (json?.extracted_items && Array.isArray(json.extracted_items)) {
        parsedObj = json;
        dataArray  = json.extracted_items;
    }
    // Format: array langsung (dari Extract from File / mandatory xlsx)
    else if (Array.isArray(json)) {
        dataArray = json;
    }
    // Format: object tunggal
    else {
        parsedObj = json;
        dataArray = [json];
    }

    // Tangkap header dokumen dari parsedObj
    if (parsedObj && !Array.isArray(parsedObj)) {
        if (parsedObj.vessel)     reqHeader.vessel     = parsedObj.vessel;
        if (parsedObj.department) reqHeader.department = parsedObj.department;
        if (parsedObj.approver)   reqHeader.approver   = parsedObj.approver;
        if (parsedObj.date)       reqHeader.date        = parsedObj.date;
        else if (parsedObj.tanggal) reqHeader.date      = parsedObj.tanggal;
    }

    // Routing: masuk ke bucket mana?
    dataArray.flat().forEach(row => {
        if (row["MAXIMUM REQUEST"] !== undefined || row["+SPARE"] !== undefined) {
            mandatoryData.push(row);
        } else if (row.cyl_1 !== undefined || row["cyl_1"] !== undefined) {
            rhData.push(row);
        } else if (row.item_name !== undefined || row.req !== undefined || row.rob !== undefined) {
            requestData.push(row);
            if (row.vessel     && reqHeader.vessel     === "-") reqHeader.vessel     = row.vessel;
            if (row.department && reqHeader.department === "-") reqHeader.department = row.department;
            if (row.approver   && reqHeader.approver   === "-") reqHeader.approver   = row.approver;
        }
    });
});

// ─── Guard: pastikan semua data tersedia ──────────────────────────────────
if (requestData.length === 0)  return [{json:{PESAN_ERROR:"❌ Data Permintaan gagal dibongkar dari PDF!"}}];
if (mandatoryData.length === 0) return [{json:{PESAN_ERROR:"❌ Data Mandatory tidak terdeteksi! Pastikan file Mandatory_[engine].xlsx tersedia di Drive."}}];
if (rhData.length === 0)        return [{json:{PESAN_ERROR:"⚠️ Data Running Hours kosong! Cek PDF Running Hours atau response Gemini."}}];

// ─── STEP 1: Filter — hanya item yang master_category cocok dengan Mandatory ─
// Filosofi baru: matching sudah dilakukan Gemini → JS hanya exact match string
const matched = [];

requestData.forEach(reqItem => {
    if (!reqItem.item_name) return;

    const reqQty = parseFloat(reqItem.req) || 0;
    if (reqQty <= 0) return;

    // master_category dari Gemini harus exact match dengan "Item Name" di Mandatory
    const reqCat = (reqItem.master_category || "").toString().trim().toUpperCase();
    if (!reqCat || reqCat === "-") return; // skip item non-mandatory

    const masterRow = mandatoryData.find(m => {
        const mName = (m["Item Name"] || "").toString().trim().toUpperCase();
        return mName !== "" && mName === reqCat;
    });

    if (!masterRow) return; // tidak ada di Mandatory → skip

    matched.push({
        req_no:       reqItem.no || "-",
        req_name:     reqItem.item_name,
        req_maker:    reqItem.maker || "-",
        req_subsystem: reqItem.subsystem || "-",
        master_name:  masterRow["Item Name"],
        qty_req:      reqQty,
        rob:          parseFloat(reqItem.rob) || 0,
        max_req:      parseFloat(masterRow["MAXIMUM REQUEST"]) || 0,
        spare:        parseFloat(masterRow["+SPARE"]) || 0,
        item_code:    masterRow["Item Code"] || "-",
    });
});

if (matched.length === 0) {
    return [{json:{PESAN_ERROR:"⚠️ Tidak ada item yang cocok dengan Mandatory. Cek hasil master_category dari Gemini."}}];
}

// ─── STEP 2: Hitung qty final + cari RH sebagai bukti pendukung ──────────
// Qty final = min(Net Req, Max Allowed)
// RH = informasi pendukung saja, tidak mempengaruhi qty

const totalCylinders = 6;

const finalData = matched.map((item, idx) => {
    const rob       = item.rob;
    const netReq    = Math.max(item.qty_req - rob, 0);
    const maxAllowed = Math.max((item.max_req + item.spare) - rob, 0);
    const finalQty  = Math.min(netReq, maxAllowed);

    let logicLabel = "";
    let rowColor   = "green";
    if (netReq > maxAllowed) {
        logicLabel = `Dipangkas: Net Req (${netReq}) > Limit (${maxAllowed}). Final = ${finalQty}`;
        rowColor   = "yellow";
    } else if (netReq === 0) {
        logicLabel = `Net Req = 0 (ROB sudah cukup).`;
        rowColor   = "blue";
    } else {
        logicLabel = `Normal. Final = ${finalQty}`;
        rowColor   = "green";
    }

    // ── Cari RH yang relevan (exact match nama master, sudah dinormalisasi Gemini) ──
    const masterNameUpper = item.master_name.toString().toUpperCase().trim();
    const rhRow = rhData.find(rh => {
        const rhDesc = (rh.deskripsi || "").toString().toUpperCase().trim();
        return rhDesc === masterNameUpper;
    }) || null;

    // Susun ringkasan RH per silinder
    let rhSummary = [];
    let unreadable = [];
    if (rhRow) {
        for (let i = 1; i <= totalCylinders; i++) {
            const raw = rhRow[`cyl_${i}`];
            if (raw === "!" || raw === "-" || raw === "?" || raw === "N/A" || raw === undefined || raw === null) {
                rhSummary.push({ cyl: i, hours: null, status: "⚠️ Tidak terbaca" });
                unreadable.push(i);
            } else {
                const hrs = parseFloat(raw) || 0;
                rhSummary.push({ cyl: i, hours: hrs, status: hrs > 0 ? `${hrs} hrs` : "0 hrs" });
            }
        }
    }

    return {
        no:            idx + 1,
        item_code:     item.item_code,
        master_name:   item.master_name,
        req_no:        item.req_no,
        req_name:      item.req_name,
        req_maker:     item.req_maker,
        req_subsystem: item.req_subsystem,
        rob:           rob,
        qty_req:       item.qty_req,
        net_req:       netReq,
        max_req:       item.max_req,
        spare:         item.spare,
        max_allowed:   maxAllowed,
        final_qty:     finalQty,
        logic_label:   logicLabel,
        row_color:     rowColor,
        rh_found:      rhRow !== null,
        rh_desc:       rhRow ? rhRow.deskripsi : "Tidak Terdeteksi",
        rh_summary:    rhSummary,
        rh_unreadable: unreadable,
    };
});

// ─── STEP 3: Build HTML Output ────────────────────────────────────────────
const colorMap = {
    green:  { bg: "#e9f7ef", text: "#1e8449", border: "#a9dfbf" },
    yellow: { bg: "#fdf2e9", text: "#b9770e", border: "#fad7a0" },
    blue:   { bg: "#eaf4fb", text: "#1a5276", border: "#a9cce3" },
};

let html = `
<div style="font-family:'Inter',system-ui,sans-serif;font-size:13px;color:#333;max-width:1250px;margin:0 auto;">

<!-- HEADER INFO -->
<div style="margin-bottom:20px;border:1px solid #e0e0e0;border-radius:8px;padding:15px;background:#fff;box-shadow:0 2px 5px rgba(0,0,0,.02)">
  <table style="width:100%;border:none;border-collapse:collapse;font-size:14px;">
    <tr>
      <td style="width:12%;color:#666;padding:4px 0">Vessel</td><td style="width:2%">:</td>
      <td style="width:36%;font-weight:700">${reqHeader.vessel}</td>
      <td style="width:12%;color:#666">Engine Type</td><td style="width:2%">:</td>
      <td style="color:#4A235A;font-weight:800;font-size:15px">${reqHeader.engine}</td>
    </tr>
    <tr>
      <td style="color:#666;padding:4px 0">Department</td><td>:</td>
      <td style="font-weight:600">${reqHeader.department}</td>
      <td style="color:#666">Date</td><td>:</td>
      <td style="font-weight:600">${reqHeader.date}</td>
    </tr>
    <tr>
      <td style="color:#666;padding:4px 0">Approver</td><td>:</td>
      <td colspan="4" style="font-weight:600">${reqHeader.approver}</td>
    </tr>
  </table>
</div>

<!-- TABEL HASIL VALIDASI -->
<div style="font-size:15px;font-weight:700;color:#4A235A;margin-bottom:12px;display:flex;align-items:center;gap:8px;">
  <span style="background:#4A235A;color:#fff;border-radius:50%;width:22px;height:22px;display:inline-flex;align-items:center;justify-content:center;font-size:12px;">✓</span>
  BARANG TERVALIDASI — HANYA ITEM YANG ADA DI MANDATORY (${finalData.length} item)
</div>

<table border="1" cellpadding="8" style="border-collapse:collapse;width:100%;text-align:center;border:1px solid #ddd;margin-bottom:30px;background:#fff;">
<thead>
  <tr style="background:#F5EEF8;color:#4A235A;font-weight:700;border-bottom:2px solid #4A235A;">
    <th style="width:3%">No</th>
    <th style="width:10%">Item Code</th>
    <th style="width:28%;text-align:left">Kategori Master &amp; Detail Dokumen</th>
    <th style="width:5%">ROB</th>
    <th style="width:6%">REQ</th>
    <th style="width:8%">NET REQ</th>
    <th style="width:9%">MAX REQ</th>
    <th style="width:7%">+SPARE</th>
    <th style="width:8%">MAX ALLOWED</th>
    <th style="width:16%">FINAL QTY &amp; STATUS</th>
  </tr>
</thead>
<tbody>
`;

finalData.forEach(row => {
    const c = colorMap[row.row_color] || colorMap.green;
    html += `
  <tr style="border-bottom:1px solid #eee;">
    <td style="color:#888">${row.no}</td>
    <td style="color:#555;font-size:11px">${row.item_code}</td>
    <td style="text-align:left;border-color:#eee;">
      <strong style="font-size:13px;color:#333">${row.master_name}</strong>
      <span style="font-size:10px;background:#F5EEF8;color:#4A235A;padding:2px 6px;border-radius:4px;margin-left:6px;border:1px solid #ebdcf5;">Mandatory</span><br>
      <div style="margin-top:6px;font-size:11px;color:#555;background:#fafafa;padding:5px 8px;border-left:3px solid #4A235A;border-radius:0 4px 4px 0;">
        <span style="color:#888">Req:</span> <strong>${row.req_name}</strong><br>
        <span style="color:#888">Part No:</span> ${row.req_maker} &nbsp;|&nbsp; <span style="color:#888">Subsystem:</span> ${row.req_subsystem}
      </div>
    </td>
    <td style="font-weight:600;color:#555">${row.rob}</td>
    <td style="font-weight:700;font-size:14px;background:${c.bg};color:${c.text}">${row.qty_req}</td>
    <td style="font-weight:700;font-size:14px;color:#4A235A">${row.net_req}</td>
    <td style="color:#555">${row.max_req}</td>
    <td style="color:#555">${row.spare}</td>
    <td style="color:#555;font-weight:600">${row.max_allowed}</td>
    <td style="background:#fafafa;vertical-align:middle;">
      <div style="font-weight:700;font-size:28px;color:${c.text};margin-bottom:4px">${row.final_qty}</div>
      <div style="font-size:11px;color:#555;background:#fff;padding:5px 7px;border-radius:5px;border:1px solid #e0e0e0;text-align:left;line-height:1.5">${row.logic_label}</div>
    </td>
  </tr>`;
});

html += `</tbody></table>

<!-- TABEL RUNNING HOURS (BUKTI PENDUKUNG) -->
<div style="font-size:15px;font-weight:700;color:#4A235A;margin-bottom:12px;border-bottom:2px solid #eee;padding-bottom:6px;">
  📋 RUNNING HOURS — BUKTI PENDUKUNG PER ITEM (${finalData.length} item)
</div>
<table style="width:100%;border-collapse:collapse;border:none;"><tr>`;

let count = 0;
finalData.forEach(item => {
    if (count > 0 && count % 2 === 0) html += `</tr><tr>`;

    let subTable = `
<table border="1" cellpadding="6" style="border-collapse:collapse;width:100%;border:1px solid #e0e0e0;background:#fff;border-radius:6px;overflow:hidden;">
  <tr style="background:#fafafa;border-bottom:1px solid #e0e0e0;">
    <th colspan="3" style="text-align:left;padding:10px 12px;line-height:1.5">
      <div style="font-size:13px;font-weight:700;color:#333">${item.master_name}</div>
      <div style="font-size:11px;color:#555;margin-top:3px">Req: ${item.req_name} &nbsp;|&nbsp; <span style="color:#888">Part:</span> ${item.req_maker}</div>
      ${item.rh_found
        ? `<div style="font-size:10px;color:#1e8449;margin-top:4px;font-weight:600">✅ RH Ditemukan: ${item.rh_desc}</div>`
        : `<div style="font-size:10px;color:#b9770e;margin-top:4px;font-weight:600">⚠️ RH tidak ditemukan untuk komponen ini</div>`
      }
    </th>
  </tr>
  <tr style="font-weight:600;font-size:11px;background:#F5EEF8;color:#4A235A;">
    <td>SILINDER</td><td>JAM KERJA (hrs)</td><td>KETERANGAN</td>
  </tr>`;

    if (item.rh_found) {
        item.rh_summary.forEach(cyl => {
            const isUnread = cyl.hours === null;
            const rowStyle = isUnread
                ? "background:#fcf3cf;color:#9c640c;font-weight:600;"
                : "color:#555;";
            subTable += `
  <tr style="font-size:12px;${rowStyle}border-color:#eee;">
    <td style="font-weight:600;color:#333">CYL ${cyl.cyl}</td>
    <td>${isUnread ? '<span style="font-weight:600">! (Tidak terbaca)</span>' : cyl.hours}</td>
    <td>${isUnread ? '⚠️ CEK' : (cyl.hours > 0 ? 'Tercatat' : '0 hrs')}</td>
  </tr>`;
        });
    } else {
        subTable += `
  <tr><td colspan="3" style="padding:10px;color:#888;font-style:italic;text-align:center;">
    Nama komponen di PDF RH tidak cocok dengan kategori master ini.<br>
    Cek normalisasi nama di prompt Analyze Running Hours.
  </td></tr>`;
    }

    subTable += `</table>`;
    html += `<td style="width:50%;padding:10px;padding-left:0;vertical-align:top;border:none;">${subTable}</td>`;
    count++;
});

if (count % 2 !== 0) html += `<td style="width:50%;border:none;"></td>`;
html += `</tr></table></div>`;

// ─── STEP 4: Split HTML untuk Google Sheets (max 40.000 char per cell) ───
const chunkSize = 40000;
const chunks = {};
for (let i = 0; i < 10; i++) {
    chunks[`html${i+1}`] = html.substring(i * chunkSize, (i+1) * chunkSize);
}

return [{
    json: {
        status: "Sukses",
        total_matched: finalData.length,
        ...chunks
    }
}];

// Node: Prepare PDF Cut List
// Mengambil hasil Analyze Items Code dan menyiapkan daftar halaman yang perlu di-cut

const inputs = $input.all();
const engineType = $('Webhook').first().json.body.engine_type || 'UNKNOWN';

let itemsData = [];

inputs.forEach(input => {
  let json = input.json;
  let dataArray = [];

  if (json.content && json.content.parts && json.content.parts[0]) {
    try {
      let cleanText = json.content.parts[0].text.replace(/```json/g, '').replace(/```/g, '').trim();
      dataArray = JSON.parse(cleanText);
    } catch(e) {}
  } else if (Array.isArray(json)) {
    dataArray = json;
  }

  if (Array.isArray(dataArray)) {
    itemsData = itemsData.concat(dataArray);
  }
});

// Deduplikasi halaman & format nama file
const uniquePages = [...new Set(itemsData.map(i => i.page).filter(p => p))];
const sortedPages = uniquePages.sort((a, b) => a - b);

const pageList = sortedPages.map(page => ({
  page_number: page,
  file_name: `${String(page).padStart(3, '0')} - ${engineType.toUpperCase().replace(/\s+/g, '_')}`,
  engine_type: engineType,
  items_on_page: itemsData.filter(i => i.page === page)
}));

if (pageList.length === 0) {
  return [{ json: { PESAN_ERROR: 'Tidak ada halaman terdeteksi dari Manual Book!' } }];
}

return pageList.map(p => ({ json: p }));
